/* ── Custom Cursor ── */
function CustomCursor() {
  const dotRef = useRef(null);
  const ringRef = useRef(null);
  const pos = useRef({x: -100, y: -100});
  const ringPos = useRef({x: -100, y: -100});
  const rafRef = useRef(null);
  const isHover = useRef(false);

  useEffect(() => {
    const onMove = (e) => {
      pos.current = { x: e.clientX, y: e.clientY };
    };
    const onDown = () => {
      dotRef.current?.classList.add('click');
      ringRef.current?.classList.add('click');
      setTimeout(() => {
        dotRef.current?.classList.remove('click');
        ringRef.current?.classList.remove('click');
      }, 150);
    };
    const onEnter = (e) => {
      const t = e.target;
      const clickable = t.closest('a,button,.c-card,.lb-close');
      if (clickable) {
        isHover.current = true;
        dotRef.current?.classList.add('hover');
        ringRef.current?.classList.add('hover');
      }
    };
    const onLeave = (e) => {
      const t = e.target;
      const clickable = t.closest('a,button,.c-card,.lb-close');
      if (clickable) {
        isHover.current = false;
        dotRef.current?.classList.remove('hover');
        ringRef.current?.classList.remove('hover');
      }
    };

    const animate = () => {
      if (dotRef.current) {
        dotRef.current.style.left = pos.current.x + 'px';
        dotRef.current.style.top = pos.current.y + 'px';
      }
      // Ring follows with lerp for smooth trailing
      ringPos.current.x += (pos.current.x - ringPos.current.x) * 0.12;
      ringPos.current.y += (pos.current.y - ringPos.current.y) * 0.12;
      if (ringRef.current) {
        ringRef.current.style.left = ringPos.current.x + 'px';
        ringRef.current.style.top = ringPos.current.y + 'px';
      }
      rafRef.current = requestAnimationFrame(animate);
    };

    window.addEventListener('mousemove', onMove, { passive: true });
    window.addEventListener('mousedown', onDown);
    document.addEventListener('mouseover', onEnter);
    document.addEventListener('mouseout', onLeave);
    rafRef.current = requestAnimationFrame(animate);

    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mousedown', onDown);
      document.removeEventListener('mouseover', onEnter);
      document.removeEventListener('mouseout', onLeave);
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, []);

  return (
    <>
      <div ref={dotRef} className="cursor-dot" />
      <div ref={ringRef} className="cursor-ring" />
    </>
  );
}

