/* ── Lightbox ── */
function Lightbox({project,onClose}){
  useEffect(()=>{
    const h=(e)=>{if(e.key==="Escape")onClose();};
    window.addEventListener("keydown",h);
    return()=>window.removeEventListener("keydown",h);
  },[onClose]);
  return(
    <div className="lb-bg" onClick={onClose}>
      <div className="lb-inner" onClick={e=>e.stopPropagation()}>
        <button className="lb-close" onClick={onClose}>✕ schließen</button>
        <div style={{borderRadius:"20px",overflow:"hidden",background:"#111518"}}>
          <div style={{position:"relative",width:"100%",paddingBottom:"56.25%",overflow:"hidden"}}>
            <img src={project.img} alt={project.title} style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover"}}/>
            <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(0,0,0,.78) 0%,transparent 55%)"}}/>
            <div style={{position:"absolute",bottom:"24px",left:"28px"}}>
              <div style={{fontFamily:"'DM Sans',sans-serif",fontSize:"10px",fontWeight:500,color:"rgba(255,255,255,.55)",letterSpacing:"0.12em",textTransform:"uppercase",marginBottom:"6px"}}>{project.category}</div>
              <h2 style={{fontFamily:project.font,fontSize:"clamp(22px,3.5vw,34px)",fontWeight:project.weight,fontStyle:project.style,color:"white",margin:0,lineHeight:1.2,letterSpacing:project.letterSpacing}}>{project.title}</h2>
            </div>
          </div>
          <div style={{padding:"22px 28px 26px"}}>
            <p style={{fontFamily:"'DM Sans',sans-serif",fontSize:"15px",fontWeight:300,color:"rgba(255,255,255,.65)",lineHeight:1.7,margin:"0 0 20px"}}>{project.desc}</p>
            <button style={{fontFamily:"'DM Sans',sans-serif",fontWeight:600,fontSize:"13px",color:"#0a0f14",background:"white",border:"none",padding:"11px 28px",borderRadius:"999px",cursor:"none"}}>
              Projekt ansehen →
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ── Carousel ── */
function HalfCircleCarousel({onLightbox,onComplete}){
  const N = PROJECTS.length;
  const TOTAL_SCROLL = 1400;
  const acc = useRef(0);
  const doneRef = useRef(false);
  const [rot, setRot] = useState(0);
  const [done, setDone] = useState(false);
  const maskRef = useRef(null);
  const touchY = useRef(0);

  const push = useCallback((delta)=>{
    if(doneRef.current) return;
    acc.current = Math.max(0, Math.min(TOTAL_SCROLL, acc.current + delta));
    const pct = acc.current / TOTAL_SCROLL;
    setRot(pct * 360);
    if(pct >= 1){
      doneRef.current = true;
      setDone(true);
      onComplete && onComplete();
    }
  },[onComplete]);

  useEffect(()=>{
    const el = maskRef.current;
    if(!el) return;
    const wh=(e)=>{ if(doneRef.current) return; e.preventDefault(); e.stopPropagation(); push(e.deltaY); };
    el.addEventListener("wheel",wh,{passive:false});
    return()=>el.removeEventListener("wheel",wh);
  },[push]);

  useEffect(()=>{
    const el = maskRef.current;
    if(!el) return;
    const ts=(e)=>{ touchY.current=e.touches[0].clientY; };
    const tm=(e)=>{
      if(doneRef.current) return;
      const dy = touchY.current - e.touches[0].clientY;
      touchY.current = e.touches[0].clientY;
      if(Math.abs(dy)>1){ e.preventDefault(); push(dy*2.2); }
    };
    el.addEventListener("touchstart",ts,{passive:true});
    el.addEventListener("touchmove",tm,{passive:false});
    return()=>{ el.removeEventListener("touchstart",ts); el.removeEventListener("touchmove",tm); };
  },[push]);

  useEffect(()=>{
    const kh=(e)=>{
      if(doneRef.current) return;
      if(!["ArrowDown","ArrowUp"].includes(e.key)) return;
      e.preventDefault();
      push(e.key==="ArrowDown" ? 110 : -110);
    };
    window.addEventListener("keydown",kh);
    return()=>window.removeEventListener("keydown",kh);
  },[push]);

  const SPAN = 148;
  const R = 43;

  /* Front card (angle near 0 = rightmost) is biggest */
  const getCardSize = (baseAngle) => {
    const absAngle = Math.abs(baseAngle);
    const normalized = absAngle / (SPAN / 2);
    return 68 - normalized * 32; /* 68% front → 36% edges */
  };
  /* Extra emphasis on the active (front) card via scale + z-index */
  const getCardEmphasis = (baseAngle) => {
    const absAngle = Math.abs(baseAngle);
    const normalized = absAngle / (SPAN / 2); /* 0 = front, 1 = edge */
    const focus = Math.max(0, 1 - normalized * 2.2); /* sharp falloff */
    return {
      scale: 1 + focus * 0.18,
      z: Math.round(focus * 100),
      shadow: focus > 0.4
    };
  };

  const progress = rot / 360;

  return(
    <div className="c-wrap anim-fade-in" style={{animationDelay:"2s"}}>
      <div className="c-mask" ref={maskRef}>
        <div className="c-ring" style={{transform:`rotate(${-rot}deg)`,transition:"transform 0.04s linear"}}>
          {PROJECTS.map((proj,i)=>{
            const baseAngle = N===1 ? 0 : -SPAN/2 + (SPAN/(N-1))*i;
            const rad = baseAngle * Math.PI / 180;
            const xPct = Math.cos(rad)*R;
            const yPct = Math.sin(rad)*R;
            const CW = getCardSize(baseAngle);
            const emp = getCardEmphasis(baseAngle);
            return(
              <div key={proj.id} className="c-card"
                onClick={()=>onLightbox(proj)}
                style={{
                  width:`${CW}%`,
                  aspectRatio:"16/9",
                  right:`calc(${xPct}% - ${CW/2}%)`,
                  top:`calc(50% + ${yPct}%)`,
                  transform:`translateY(-50%) rotate(${rot}deg) scale(${emp.scale})`,
                  zIndex: emp.z,
                  boxShadow: emp.shadow
                    ? "0 18px 60px rgba(0,0,0,0.75), 0 4px 16px rgba(0,0,0,0.5)"
                    : "0 8px 32px rgba(0,0,0,0.55)",
                  transition: "box-shadow .35s ease, width .45s cubic-bezier(.16,1,.3,1), transform .04s linear",
                }}
              >
                <img src={proj.img} alt={proj.title}/>
                <div className="c-label">
                  <div style={{fontFamily:"'DM Sans',sans-serif",fontSize:"9px",fontWeight:500,color:"rgba(255,255,255,.5)",letterSpacing:"0.12em",textTransform:"uppercase",marginBottom:"3px"}}>{proj.category}</div>
                  <div style={{fontFamily:proj.font,fontSize:"14px",fontWeight:proj.weight,fontStyle:proj.style,color:proj.accentColor,letterSpacing:proj.letterSpacing}}>{proj.title}</div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Left edge blend into warm hero bg */}
        <div style={{position:"absolute",inset:0,pointerEvents:"none",zIndex:2,background:"linear-gradient(to right,rgba(28,20,14,0.7) 0%,transparent 22%)"}}/>
        {/* Top/bottom blend */}
        <div style={{position:"absolute",inset:0,pointerEvents:"none",zIndex:2,background:"linear-gradient(to bottom,rgba(28,20,14,0.5) 0%,transparent 12%,transparent 88%,rgba(28,20,14,0.5) 100%)"}}/>

        {/* Progress indicator */}
        {!done&&(
          <div style={{position:"absolute",right:"14px",top:"50%",transform:"translateY(-50%)",display:"flex",flexDirection:"column",alignItems:"center",gap:"3px",opacity:.6,zIndex:3}}>
            <div style={{fontFamily:"'DM Sans',sans-serif",fontSize:"10px",color:acc.current>0?"rgba(255,255,255,.7)":"rgba(255,255,255,.2)",marginBottom:"4px"}}>↑</div>
            {Array.from({length:20}).map((_,i)=>(
              <div key={i} style={{width:"2px",height:"5px",borderRadius:"1px",background:progress*20>i?"rgba(255,255,255,.85)":"rgba(255,255,255,.15)",transition:"background 0.1s"}}/>
            ))}
            <div style={{fontFamily:"'DM Sans',sans-serif",fontSize:"10px",color:acc.current<TOTAL_SCROLL?"rgba(255,255,255,.7)":"rgba(255,255,255,.2)",marginTop:"4px"}}>↓</div>
          </div>
        )}
      </div>
    </div>
  );
}

